    if note_id not in notes:
        abort(404)
    del notes[note_id]
    return "", 204


# Simple JSON error responses
@app.errorhandler(400)
def bad_request(e):
    return jsonify(error="bad_request"), 400


@app.errorhandler(404)
def not_found(e):
    return jsonify(error="not_found"), 404


if __name__ == "__main__":
    app.run(debug=True)
